# capstone_agent.py

import os
import re
import json
import time
import uuid
import math
import logging
import hashlib
from dataclasses import dataclass, field, asdict
from contextlib import contextmanager
from typing import Any, Optional
from pathlib import Path
from openai import OpenAI

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger('capstone-agent')

client = OpenAI()

SYSTEM_PROMPT = (
    'You are a helpful, accurate, and safe AI assistant. '
    'You have access to tools. Always prefer tool results over prior knowledge '
    'when answering factual questions. Never fabricate data. '
    'If you are unsure, say so.'
)
SYSTEM_PROMPT_HASH = hashlib.sha256(SYSTEM_PROMPT.encode()).hexdigest()[:8]


# ══════════════════════════════════════════════════════════════
# 1. GUARDRAILS
# ══════════════════════════════════════════════════════════════

PII_PATTERNS = [
    (re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'), '[EMAIL]'),
    (re.compile(r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b'), '[PHONE]'),
    (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '[SSN]'),
]

INJECTION_PATTERNS = [
    re.compile(p, re.IGNORECASE) for p in [
        r'ignore (all )?previous instructions',
        r'system (prompt|override)',
        r'you are now',
        r'disregard (your )?training',
    ]
]

ALLOWED_TOPICS = ['software engineering', 'java', 'python', 'kafka', 'databases',
                   'system design', 'ai', 'machine learning', 'general question']

@dataclass
class GuardResult:
    allowed: bool
    text: str
    reason: str = ''


def mask_pii(text: str) -> str:
    for pattern, replacement in PII_PATTERNS:
        text = pattern.sub(replacement, text)
    return text


def check_injection(text: str) -> bool:
    return any(p.search(text) for p in INJECTION_PATTERNS)


def input_guard(text: str) -> GuardResult:
    if check_injection(text):
        return GuardResult(allowed=False, text=text, reason='prompt_injection')
    clean = mask_pii(text)
    return GuardResult(allowed=True, text=clean)


def output_guard(text: str) -> GuardResult:
    clean = mask_pii(text)
    # Block outputs that look like the agent is revealing its system prompt
    if 'system prompt' in clean.lower() and 'helpful' in clean.lower():
        return GuardResult(allowed=False, text='', reason='system_prompt_leak')
    return GuardResult(allowed=True, text=clean)


# ══════════════════════════════════════════════════════════════
# 2. TOOLS
# ══════════════════════════════════════════════════════════════

@dataclass
class ToolSpec:
    name: str
    description: str
    parameters: dict

    def to_openai(self) -> dict:
        return {
            'type': 'function',
            'function': {
                'name': self.name,
                'description': self.description,
                'parameters': self.parameters,
            }
        }


class ToolRegistry:
    def __init__(self):
        self._tools: dict[str, tuple[ToolSpec, callable]] = {}
        self._call_log: list[dict] = []

    def register(self, spec: ToolSpec, handler: callable):
        self._tools[spec.name] = (spec, handler)

    def specs(self) -> list[dict]:
        return [spec.to_openai() for spec, _ in self._tools.values()]

    def call(self, name: str, args: dict) -> dict:
        if name not in self._tools:
            return {'error': f'Unknown tool: {name}'}
        _, handler = self._tools[name]
        start = time.time()
        try:
            result = handler(**args)
            self._call_log.append({'tool': name, 'args': args,
                                    'success': True, 'ms': int((time.time()-start)*1000)})
            return result
        except Exception as e:
            self._call_log.append({'tool': name, 'args': args,
                                    'success': False, 'error': str(e)})
            return {'error': str(e)}


def make_registry() -> ToolRegistry:
    registry = ToolRegistry()

    registry.register(
        ToolSpec(
            name='search_knowledge_base',
            description='Search the internal knowledge base for technical documentation.',
            parameters={
                'type': 'object',
                'properties': {
                    'query': {'type': 'string', 'description': 'Search query'},
                },
                'required': ['query'],
            }
        ),
        handler=lambda query: {
            'results': [f'[KB] Relevant article about: {query}'],
            'count': 1,
        }
    )

    registry.register(
        ToolSpec(
            name='calculate',
            description='Perform arithmetic calculations.',
            parameters={
                'type': 'object',
                'properties': {
                    'expression': {'type': 'string', 'description': 'Math expression to evaluate'},
                },
                'required': ['expression'],
            }
        ),
        handler=lambda expression: {
            'result': eval(expression, {'__builtins__': {}},  # restricted eval
                           {'abs': abs, 'round': round, 'min': min, 'max': max})
        }
    )

    return registry


# ══════════════════════════════════════════════════════════════
# 3. MEMORY
# ══════════════════════════════════════════════════════════════

@dataclass
class MemoryEntry:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    content: str = ''
    embedding: list[float] = field(default_factory=list)
    created_at: float = field(default_factory=time.time)
    access_count: int = 0

    def score(self, similarity: float) -> float:
        age_hours = (time.time() - self.created_at) / 3600
        recency = math.exp(-0.05 * age_hours)
        return 0.7 * similarity + 0.3 * recency


class MemoryStore:
    def __init__(self, path: str = 'capstone_memory.json', max_entries: int = 500):
        self.path = Path(path)
        self.max_entries = max_entries
        self.entries: list[MemoryEntry] = []
        self._load()

    def _embed(self, text: str) -> list[float]:
        resp = client.embeddings.create(model='text-embedding-3-small', input=text[:4000])
        return resp.data[0].embedding

    def _cosine(self, a: list[float], b: list[float]) -> float:
        dot = sum(x*y for x, y in zip(a, b))
        return dot / (math.sqrt(sum(x**2 for x in a)) * math.sqrt(sum(x**2 for x in b)) + 1e-9)

    def add(self, content: str):
        entry = MemoryEntry(content=content, embedding=self._embed(content))
        self.entries.append(entry)
        if len(self.entries) > self.max_entries:
            self.entries = self.entries[-self.max_entries:]
        self._save()

    def retrieve(self, query: str, top_k: int = 3, min_sim: float = 0.60) -> list[str]:
        if not self.entries:
            return []
        q_emb = self._embed(query)
        scored = [
            (e, e.score(self._cosine(q_emb, e.embedding)))
            for e in self.entries if e.embedding
        ]
        scored.sort(key=lambda x: x[1], reverse=True)
        results = []
        for entry, score in scored[:top_k]:
            if score >= min_sim:
                entry.access_count += 1
                results.append(entry.content[:300])
        self._save()
        return results

    def _save(self):
        self.path.write_text(json.dumps([asdict(e) for e in self.entries], indent=2))

    def _load(self):
        if self.path.exists():
            self.entries = [MemoryEntry(**d) for d in json.loads(self.path.read_text())]


# ══════════════════════════════════════════════════════════════
# 4. OBSERVABILITY
# ══════════════════════════════════════════════════════════════

COST_PER_1K = {'gpt-4o-mini': (0.00015, 0.0006), 'gpt-4o': (0.0025, 0.01)}

@dataclass
class Trace:
    trace_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    start_time: float = field(default_factory=time.time)
    end_time: float = 0.0
    steps: int = 0
    total_input_tokens: int = 0
    total_output_tokens: int = 0
    model: str = 'gpt-4o-mini'
    tool_calls: list[str] = field(default_factory=list)
    prompt_hash: str = ''

    @property
    def latency_ms(self) -> int:
        return int((self.end_time - self.start_time) * 1000)

    @property
    def cost_usd(self) -> float:
        inp, out = COST_PER_1K.get(self.model, (0.003, 0.006))
        return self.total_input_tokens / 1000 * inp + self.total_output_tokens / 1000 * out

    def finish(self):
        self.end_time = time.time()

    def summary(self) -> dict:
        return {
            'trace_id': self.trace_id,
            'latency_ms': self.latency_ms,
            'steps': self.steps,
            'tokens': self.total_input_tokens + self.total_output_tokens,
            'cost_usd': round(self.cost_usd, 6),
            'tools_used': self.tool_calls,
            'prompt_hash': self.prompt_hash,
        }


# ══════════════════════════════════════════════════════════════
# 5. CHECKPOINTING
# ══════════════════════════════════════════════════════════════

@dataclass
class Checkpoint:
    task_id: str
    completed_steps: list[dict] = field(default_factory=list)
    final_answer: Optional[str] = None
    saved_at: float = field(default_factory=time.time)


class CheckpointStore:
    def __init__(self, path: str = 'checkpoints'):
        self.dir = Path(path)
        self.dir.mkdir(exist_ok=True)

    def save(self, cp: Checkpoint):
        (self.dir / f'{cp.task_id}.json').write_text(
            json.dumps(asdict(cp), indent=2)
        )

    def load(self, task_id: str) -> Optional[Checkpoint]:
        p = self.dir / f'{task_id}.json'
        if p.exists():
            return Checkpoint(**json.loads(p.read_text()))
        return None

    def delete(self, task_id: str):
        p = self.dir / f'{task_id}.json'
        if p.exists():
            p.unlink()


# ══════════════════════════════════════════════════════════════
# 6. CORE AGENT
# ══════════════════════════════════════════════════════════════

class CapstoneAgent:
    def __init__(
        self,
        registry: ToolRegistry,
        memory: MemoryStore,
        checkpoints: CheckpointStore,
        model: str = 'gpt-4o-mini',
        max_steps: int = 10,
    ):
        self.registry = registry
        self.memory = memory
        self.checkpoints = checkpoints
        self.model = model
        self.max_steps = max_steps

    def run(self, user_input: str, task_id: Optional[str] = None) -> dict:
        trace = Trace(model=self.model, prompt_hash=SYSTEM_PROMPT_HASH)
        task_id = task_id or trace.trace_id

        # ── 1. Input guardrail ────────────────────────────────────────────
        guard = input_guard(user_input)
        if not guard.allowed:
            trace.finish()
            return {
                'answer': 'I cannot process that request.',
                'blocked_reason': guard.reason,
                'trace': trace.summary(),
            }
        clean_input = guard.text

        # ── 2. Resume from checkpoint if available ────────────────────────
        cp = self.checkpoints.load(task_id)
        completed_step_ids = set()
        messages = [{'role': 'system', 'content': SYSTEM_PROMPT}]

        if cp and cp.final_answer:
            logger.info(f'Checkpoint has final answer — returning immediately')
            trace.finish()
            return {'answer': cp.final_answer, 'trace': trace.summary(), 'from_checkpoint': True}

        if cp:
            logger.info(f'Resuming from checkpoint: {len(cp.completed_steps)} steps done')
            for step in cp.completed_steps:
                completed_step_ids.add(step.get('step_id', ''))
                messages.append({'role': 'assistant', 'content': step.get('content', '')})
                if step.get('tool_result'):
                    messages.append({'role': 'user', 'content': step['tool_result']})

        # ── 3. Memory retrieval ───────────────────────────────────────────
        memories = []
        try:
            memories = self.memory.retrieve(clean_input, top_k=3)
        except Exception as e:
            logger.warning(f'Memory retrieval failed (degraded): {e}')

        if memories:
            memory_block = 'RELEVANT PAST EXPERIENCES:\n' + '\n'.join(f'- {m}' for m in memories)
            messages[0]['content'] += f'\n\n{memory_block}'

        messages.append({'role': 'user', 'content': clean_input})

        # ── 4. Agentic loop ───────────────────────────────────────────────
        answer = ''
        for step_num in range(self.max_steps):
            trace.steps += 1
            try:
                resp = client.chat.completions.create(
                    model=self.model,
                    messages=messages,
                    tools=self.registry.specs(),
                    tool_choice='auto',
                    max_tokens=1500,
                )
            except Exception as e:
                logger.error(f'LLM call failed at step {step_num}: {e}')
                answer = 'I encountered an error. Please try again.'
                break

            usage = resp.usage
            trace.total_input_tokens += usage.prompt_tokens
            trace.total_output_tokens += usage.completion_tokens

            msg = resp.choices[0].message
            messages.append(msg.model_dump(exclude_unset=True))

            # No tool call — final answer
            if not msg.tool_calls:
                answer = msg.content or ''
                break

            # Process tool calls
            step_tool_results = []
            for tc in msg.tool_calls:
                tool_name = tc.function.name
                args = json.loads(tc.function.arguments)
                trace.tool_calls.append(tool_name)
                logger.info(f'Step {step_num}: calling {tool_name}({args})')

                result = self.registry.call(tool_name, args)
                result_str = json.dumps(result)
                step_tool_results.append(result_str)

                messages.append({
                    'role': 'tool',
                    'tool_call_id': tc.id,
                    'content': result_str,
                })

            # Checkpoint after each step
            cp_step = {
                'step_id': f'step_{step_num}',
                'content': msg.content or '',
                'tool_result': step_tool_results[0] if step_tool_results else None,
            }
            cp_data = Checkpoint(
                task_id=task_id,
                completed_steps=(cp.completed_steps if cp else []) + [cp_step],
            )
            try:
                self.checkpoints.save(cp_data)
            except Exception as e:
                logger.warning(f'Checkpoint save failed: {e}')

        else:
            answer = 'Task exceeded maximum steps. Partial results may be incomplete.'

        # ── 5. Output guardrail ───────────────────────────────────────────
        out_guard = output_guard(answer)
        safe_answer = out_guard.text if out_guard.allowed else (
            'My response was filtered for safety. Please rephrase your question.'
        )

        # ── 6. Store to memory ────────────────────────────────────────────
        try:
            self.memory.add(
                f'User asked: {clean_input[:200]}\n'
                f'Agent answered: {safe_answer[:200]}'
            )
        except Exception as e:
            logger.warning(f'Memory store failed (degraded): {e}')

        # ── 7. Mark checkpoint complete ───────────────────────────────────
        final_cp = Checkpoint(
            task_id=task_id,
            completed_steps=cp_data.completed_steps if 'cp_data' in dir() else [],
            final_answer=safe_answer,
        )
        self.checkpoints.save(final_cp)

        trace.finish()
        logger.info(f'Trace: {json.dumps(trace.summary())}')

        return {
            'answer': safe_answer,
            'task_id': task_id,
            'trace': trace.summary(),
        }


# ══════════════════════════════════════════════════════════════
# 7. DEMO HARNESS
# ══════════════════════════════════════════════════════════════

def build_agent() -> CapstoneAgent:
    return CapstoneAgent(
        registry=make_registry(),
        memory=MemoryStore('capstone_memory.json'),
        checkpoints=CheckpointStore('capstone_checkpoints'),
        model='gpt-4o-mini',
        max_steps=8,
    )


if __name__ == '__main__':
    agent = build_agent()

    questions = [
        'What is the difference between Kafka and RabbitMQ for event streaming?',
        'Calculate 2 ** 10 + 50',
        'Search the knowledge base for Java garbage collection tuning tips.',
    ]

    for q in questions:
        print(f'\n>>> {q}')
        result = agent.run(q)
        print(f'Answer: {result["answer"]}')
        print(f'Trace: {json.dumps(result["trace"], indent=2)}')
